import{_ as e,o as t,c as n,ag as i}from"./chunks/framework.B45ElpZ1.js";const u=JSON.parse('{"title":"Channels & API","description":"Current notes on tradecli interaction channels beyond the main TUI.","frontmatter":{"title":"Channels & API","description":"Current notes on tradecli interaction channels beyond the main TUI.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/channels-api"}]]},"headers":[],"relativePath":"guides/channels-api.md","filePath":"guides/channels-api.md"}'),r={name:"guides/channels-api.md"};function s(o,a,l,h,c,p){return t(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="channels-api" tabindex="-1">Channels &amp; API <a class="header-anchor" href="#channels-api" aria-label="Permalink to &quot;Channels &amp; API&quot;">​</a></h1><p>The supported launch surface is the interactive TUI:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span></span></code></pre></div><p>Other channels are treated as integration surfaces around the local runtime, not as the default path for a new user.</p><div class="warning custom-block"><p class="custom-block-title">Current status</p><p>The TUI is the documented primary channel. Telegram, WhatsApp, and raw gateway usage are not part of the normal Quick Start path.</p></div><h2 id="what-is-a-channel" tabindex="-1">What is a channel <a class="header-anchor" href="#what-is-a-channel" aria-label="Permalink to &quot;What is a channel&quot;">​</a></h2><p>A channel is an interface that can send work into tradecli or receive output from it. The channel should not change the safety model: broker credentials remain local, and actions that move money still require explicit approval.</p><h2 id="the-tui-channel" tabindex="-1">The TUI channel <a class="header-anchor" href="#the-tui-channel" aria-label="Permalink to &quot;The TUI channel&quot;">​</a></h2><p>The TUI is the main product surface. It handles persona and workflow selection, Office Mode, local tool visibility, setup prompts, and review before risky actions.</p><h2 id="telegram" tabindex="-1">Telegram <a class="header-anchor" href="#telegram" aria-label="Permalink to &quot;Telegram&quot;">​</a></h2><p>Telegram is not required for normal use. Treat it as an external integration surface only when explicitly configured for a workflow.</p><h2 id="whatsapp" tabindex="-1">WhatsApp <a class="header-anchor" href="#whatsapp" aria-label="Permalink to &quot;WhatsApp&quot;">​</a></h2><p>WhatsApp is not required for normal use. Treat it as an external integration surface only when explicitly configured for a workflow.</p><h2 id="gateway-http-api" tabindex="-1">Gateway HTTP API <a class="header-anchor" href="#gateway-http-api" aria-label="Permalink to &quot;Gateway HTTP API&quot;">​</a></h2><p>The local gateway exists to support tradecli workflows and sidecars. It is not the recommended first interface for users. Start with <code>tradecli</code>, then use documented integration paths only when a workflow calls for them.</p>',15)])])}const m=e(r,[["render",s]]);export{u as __pageData,m as default};
